/**
 * Common validators shared across services.
 *
 * All functions are pure — no side effects, no database calls.
 * They receive data and throw if validation fails.
 */

import type { User } from '../models/user.js';

/**
 * Validate that a user exists (was found by a prior lookup).
 * Throws if the user is undefined.
 */
export function validateUserExists(user: User | undefined, userId: string): asserts user is User {
  if (!user) {
    throw new Error(`User not found: ${userId}`);
  }
}

/**
 * User validators — pure validation functions for user operations.
 *
 * No side effects, no database calls. Each function receives
 * already-fetched data and throws if validation fails.
 */

import type { User } from '../models/user.js';

/**
 * Validate that an email is not already taken by another user.
 * Used during user creation.
 */
export function validateEmailNotTaken(email: string, existingUser: User | undefined): void {
  if (existingUser) {
    throw new Error(`User with email ${email} already exists`);
  }
}

/**
 * Validate that an email is not already in use by a different user.
 * Used during user update when the email is being changed.
 */
export function validateEmailNotInUse(email: string, existingUser: User | undefined): void {
  if (existingUser) {
    throw new Error(`Email ${email} is already in use`);
  }
}

/**
 * Order validators — pure validation functions for order operations.
 *
 * No side effects, no database calls. Each function receives
 * already-fetched data and throws if validation fails.
 */

import type { Order, OrderItem, OrderStatus } from '../models/order.js';

/**
 * Valid status transitions for orders.
 */
const STATUS_TRANSITIONS: Record<OrderStatus, OrderStatus[]> = {
  pending: ['confirmed', 'cancelled'],
  confirmed: ['shipped', 'cancelled'],
  shipped: ['delivered'],
  delivered: [],
  cancelled: [],
};

/**
 * Validate that an order has at least one item.
 */
export function validateOrderHasItems(items: OrderItem[]): void {
  if (items.length === 0) {
    throw new Error('Order must have at least one item');
  }
}

/**
 * Validate that an order exists (was found by a prior lookup).
 */
export function validateOrderExists(order: Order | undefined, orderId: string): asserts order is Order {
  if (!order) {
    throw new Error(`Order not found: ${orderId}`);
  }
}

/**
 * Validate that a status transition is allowed.
 */
export function validateStatusTransition(from: OrderStatus, to: OrderStatus): void {
  if (!STATUS_TRANSITIONS[from].includes(to)) {
    throw new Error(`Invalid status transition: ${from} -> ${to}`);
  }
}

