import { describe, it, expect } from 'vitest';
import { validateUserExists } from '../../src/validators/common.validator.js';
import type { User } from '../../src/models/user.js';

describe('common validators', () => {
  describe('validateUserExists', () => {
    const user: User = {
      id: 'user-1',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    };

    it('should not throw when user exists', () => {
      expect(() => validateUserExists(user, 'user-1')).not.toThrow();
    });

    it('should throw when user is undefined', () => {
      expect(() => validateUserExists(undefined, 'user-99')).toThrow(
        'User not found: user-99',
      );
    });
  });
});

import { describe, it, expect } from 'vitest';
import { validateEmailNotTaken, validateEmailNotInUse } from '../../src/validators/user.validator.js';
import type { User } from '../../src/models/user.js';

const existingUser: User = {
  id: 'user-1',
  name: 'Alice',
  email: 'alice@example.com',
  role: 'member',
  createdAt: new Date(),
  updatedAt: new Date(),
};

describe('user validators', () => {
  describe('validateEmailNotTaken', () => {
    it('should not throw when no existing user found', () => {
      expect(() => validateEmailNotTaken('new@example.com', undefined)).not.toThrow();
    });

    it('should throw when email is already taken', () => {
      expect(() => validateEmailNotTaken('alice@example.com', existingUser)).toThrow(
        'User with email alice@example.com already exists',
      );
    });
  });

  describe('validateEmailNotInUse', () => {
    it('should not throw when no existing user found', () => {
      expect(() => validateEmailNotInUse('new@example.com', undefined)).not.toThrow();
    });

    it('should throw when email is already in use', () => {
      expect(() => validateEmailNotInUse('alice@example.com', existingUser)).toThrow(
        'Email alice@example.com is already in use',
      );
    });
  });
});

import { describe, it, expect } from 'vitest';
import {
  validateOrderHasItems,
  validateOrderExists,
  validateStatusTransition,
} from '../../src/validators/order.validator.js';
import type { Order } from '../../src/models/order.js';

describe('order validators', () => {
  describe('validateOrderHasItems', () => {
    it('should not throw when items are present', () => {
      expect(() =>
        validateOrderHasItems([
          { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
        ]),
      ).not.toThrow();
    });

    it('should throw when items array is empty', () => {
      expect(() => validateOrderHasItems([])).toThrow(
        'Order must have at least one item',
      );
    });
  });

  describe('validateOrderExists', () => {
    const order: Order = {
      id: 'order-1',
      userId: 'user-1',
      items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
      total: 10,
      status: 'pending',
      createdAt: new Date(),
      updatedAt: new Date(),
    };

    it('should not throw when order exists', () => {
      expect(() => validateOrderExists(order, 'order-1')).not.toThrow();
    });

    it('should throw when order is undefined', () => {
      expect(() => validateOrderExists(undefined, 'order-99')).toThrow(
        'Order not found: order-99',
      );
    });
  });

  describe('validateStatusTransition', () => {
    it('should allow pending -> confirmed', () => {
      expect(() => validateStatusTransition('pending', 'confirmed')).not.toThrow();
    });

    it('should allow pending -> cancelled', () => {
      expect(() => validateStatusTransition('pending', 'cancelled')).not.toThrow();
    });

    it('should allow confirmed -> shipped', () => {
      expect(() => validateStatusTransition('confirmed', 'shipped')).not.toThrow();
    });

    it('should allow confirmed -> cancelled', () => {
      expect(() => validateStatusTransition('confirmed', 'cancelled')).not.toThrow();
    });

    it('should allow shipped -> delivered', () => {
      expect(() => validateStatusTransition('shipped', 'delivered')).not.toThrow();
    });

    it('should reject pending -> delivered', () => {
      expect(() => validateStatusTransition('pending', 'delivered')).toThrow(
        'Invalid status transition: pending -> delivered',
      );
    });

    it('should reject delivered -> any', () => {
      expect(() => validateStatusTransition('delivered', 'pending')).toThrow(
        'Invalid status transition',
      );
    });

    it('should reject cancelled -> any', () => {
      expect(() => validateStatusTransition('cancelled', 'confirmed')).toThrow(
        'Invalid status transition',
      );
    });
  });
});
